func solve(grid [][]int64, k int64) int64 {
	m := len(grid)
	n := len(grid[0])
	visited := make([][]bool, m)
	for i := range visited {
		visited[i] = make([]bool, n)
	}
	count := int64(0)

	var dfs func(int, int, int64, int64, map[int64]int64)
	dfs = func(i, j, total, mod int64, hash map[int64]int64) {
		if i < 0 || i >= m || j < 0 || j >= n || visited[i][j] || grid[i][j] == 0 {
			return
		}
		visited[i][j] = true
		total += grid[i][j]
		mod = total % k
		hash[mod] = hash[mod] + 1
		dfs(i-1, j, total, mod, hash)
		dfs(i+1, j, total, mod, hash)
		dfs(i, j-1, total, mod, hash)
		dfs(i, j+1, total, mod, hash)
	}

	for i := 0; i < m; i++ {
		for j := 0; j < n; j++ {
			if grid[i][j] > 0 && !visited[i][j] {
				hash := make(map[int64]int64)
				dfs(int(i), int(j), 0, 0, hash)
				count += hash[0]
			}
		}
	}
	return count
}
